#!/usr/bin/perl
use strict;
use warnings;
use Carp;
use File::Basename;
use File::Spec;

# ============================================================================
# Extensible Perl Application with Plugin Support
# Loads and executes plugin code from configuration files safely
# ============================================================================

my $PLUGIN_DIR = $ENV{PLUGIN_DIR} || './plugins';
my $ALLOWED_PLUGIN_DIR;
my %loaded_plugins;
my @plugin_log;

# Initialize the allowed plugin directory (resolve to absolute path)
BEGIN {
    $ALLOWED_PLUGIN_DIR = File::Spec->rel2abs($ENV{PLUGIN_DIR} || './plugins');
}

# ----------------------------------------------------------------------------
# Logging utility
# ----------------------------------------------------------------------------
sub log_message {
    my ($level, $message) = @_;
    my $timestamp = localtime();
    my $entry = "[$timestamp] [$level] $message";
    push @plugin_log, $entry;
    print STDERR "$entry\n";
}

# ----------------------------------------------------------------------------
# Validate plugin code before execution
# Checks for dangerous operations and enforces a safety policy
# ----------------------------------------------------------------------------
sub validate_plugin_code {
    my ($code, $plugin_name) = @_;

    # List of forbidden patterns that could be dangerous
    my @forbidden_patterns = (
        qr/\bsystem\s*\(/,           # system() calls
        qr/\bexec\s*\(/,             # exec() calls
        qr/\b`[^`]*`/,              # backtick execution
        qr/\bqx\s*[\(\{\/]/,        # qx// execution
        qr/\bopen\s*\(\s*\w+\s*,\s*["']\s*\|/,  # piped open
        qr/\bopen\s*\(\s*\w+\s*,\s*["'][^"']*["']\s*,\s*["']\s*\|-/,  # 3-arg piped open
        qr/\bunlink\s*\(/,           # file deletion
        qr/\brmdir\s*\(/,            # directory removal
        qr/\brename\s*\(/,           # file renaming
        qr/\bchmod\s*\(/,            # permission changes
        qr/\bchown\s*\(/,            # ownership changes
        qr/\brequire\s+/,            # dynamic require
        qr/\buse\s+/,                # use statements (could load anything)
        qr/\bBEGIN\s*\{/,            # BEGIN blocks
        qr/\bEND\s*\{/,              # END blocks
        qr/\bINIT\s*\{/,             # INIT blocks
        qr/\bCHECK\s*\{/,            # CHECK blocks
        qr/\bUNITCHECK\s*\{/,        # UNITCHECK blocks
        qr/\beval\s*\(/,             # nested eval (prevent eval chains)
        qr/\beval\s*\{/,             # nested eval blocks
        qr/\beval\s+["']/,           # nested string eval
        qr/\bDO\s+["']/i,            # do "file"
        qr/\bsymlink\s*\(/,          # symlink creation
        qr/\bsocket\s*\(/,           # socket operations
        qr/\bconnect\s*\(/,          # network connections
        qr/\bbind\s*\(/,             # binding sockets
        qr/\blisten\s*\(/,           # listening on sockets
        qr/\baccept\s*\(/,           # accepting connections
        qr/\bfork\s*\(/,             # forking processes
        qr/\bkill\s*\(/,             # sending signals
        qr/\bglob\s*\(/,             # glob operations
        qr/\bENV\s*\{/,              # environment variable access
        qr/\$ENV\b/,                 # environment variable access
        qr/\bFile::|\bIO::|\bNet::/, # dangerous module references
    );

    for my $pattern (@forbidden_patterns) {
        if ($code =~ $pattern) {
            my $matched = $&;
            log_message('ERROR', "Plugin '$plugin_name' contains forbidden pattern: $matched");
            return (0, "Forbidden pattern detected: $matched");
        }
    }

    # Check code length limit (prevent resource exhaustion)
    my $max_code_length = 50_000;  # 50KB limit
    if (length($code) > $max_code_length) {
        log_message('ERROR', "Plugin '$plugin_name' exceeds maximum code length ($max_code_length bytes)");
        return (0, "Code exceeds maximum length of $max_code_length bytes");
    }

    # Basic syntax check using eval in a restricted manner
    {
        no warnings 'all';
        my $syntax_check = eval "sub { no strict; $code; return 1; }; 1;";
        if (!$syntax_check) {
            my $err = $@;
            log_message('ERROR', "Plugin '$plugin_name' has syntax errors: $err");
            return (0, "Syntax error: $err");
        }
    }

    return (1, "Validation passed");
}

# ----------------------------------------------------------------------------
# Validate file path to prevent directory traversal
# ----------------------------------------------------------------------------
sub validate_plugin_path {
    my ($filepath) = @_;

    my $abs_path = File::Spec->rel2abs($filepath);
    my $real_dir = File::Spec->rel2abs(dirname($abs_path));

    # Ensure the file is within the allowed plugin directory
    unless ($real_dir =~ /^\Q$ALLOWED_PLUGIN_DIR\E/) {
        log_message('ERROR', "Path traversal attempt detected: $filepath");
        return (0, "Plugin file must be within the designated plugin directory");
    }

    # Check file extension
    unless ($abs_path =~ /\.plugin\.conf$/) {
        log_message('ERROR', "Invalid plugin file extension: $filepath");
        return (0, "Plugin files must have .plugin.conf extension");
    }

    # Check that the file exists and is a regular file
    unless (-f $abs_path && -r $abs_path) {
        log_message('ERROR', "Plugin file not found or not readable: $filepath");
        return (0, "Plugin file not found or not readable");
    }

    # Check file ownership and permissions (should not be world-writable)
    my @stat = stat($abs_path);
    if ($stat[2] & 002) {  # world-writable check
        log_message('ERROR', "Plugin file is world-writable (insecure): $filepath");
        return (0, "Plugin file must not be world-writable");
    }

    return (1, $abs_path);
}

# ----------------------------------------------------------------------------
# Load plugin code from a configuration file
# Expected format:
#   # Plugin: <name>
#   # Version: <version>
#   # Description: <description>
#   <perl code>
# ----------------------------------------------------------------------------
sub load_plugin_from_file {
    my ($filepath) = @_;

    # Validate the file path
    my ($path_valid, $path_result) = validate_plugin_path($filepath);
    unless ($path_valid) {
        return { success => 0, error => $path_result };
    }

    my $abs_path = $path_result;

    # Read the file
    open(my $fh, '<', $abs_path) or do {
        log_message('ERROR', "Cannot open plugin file: $abs_path: $!");
        return { success => 0, error => "Cannot open file: $!" };
    };

    my $content = do { local $/; <$fh> };
    close($fh);

    # Parse metadata from comments
    my %metadata;
    while ($content =~ /^#\s*(Plugin|Version|Description|Author):\s*(.+)$/mg) {
        $metadata{lc($1)} = $2;
    }

    my $plugin_name = $metadata{plugin} || basename($filepath, '.plugin.conf');

    # Remove comment lines to get pure code
    my $code = '';
    for my $line (split /\n/, $content) {
        next if $line =~ /^\s*#/;
        $code .= "$line\n";
    }

    $code =~ s/^\s+|\s+$//g;

    unless ($code) {
        log_message('WARN', "Plugin '$plugin_name' contains no executable code");
        return { success => 0, error => "No executable code found" };
    }

    return {
        success  => 1,
        name     => $plugin_name,
        version  => $metadata{version} || '0.0.1',
        description => $metadata{description} || 'No description',
        author   => $metadata{author} || 'Unknown',
        code     => $code,
        filepath => $abs_path,
    };
}

# ----------------------------------------------------------------------------
# Execute plugin code in a controlled environment
# Uses eval() with timeout and error handling
# ----------------------------------------------------------------------------
sub execute_plugin {
    my ($plugin) = @_;

    unless (ref $plugin eq 'HASH' && $plugin->{code}) {
        log_message('ERROR', "Invalid plugin structure passed to execute_plugin");
        return { success => 0, error => "Invalid plugin structure" };
    }

    my $plugin_name = $plugin->{name} || 'unknown';
    my $plugin_code = $plugin->{code};

    log_message('INFO', "Validating plugin '$plugin_name'...");

    # Validate the code before execution
    my ($is_valid, $validation_msg) = validate_plugin_code($plugin_code, $plugin_name);
    unless ($is_valid) {
        return { success => 0, error => "Validation failed: $validation_msg" };
    }

    log_message('INFO', "Executing plugin '$plugin_name' (v$plugin->{version})...");

    # Create a sandboxed namespace for the plugin
    my $namespace = "PluginSandbox::${plugin_name}";
    $namespace =~ s/[^a-zA-Z0-9_:]/_/g;  # sanitize namespace

    # Wrap the plugin code in a namespace and provide limited API
    my $wrapped_code = qq{
        package $namespace;
        use strict;
        use warnings;

        # Limited API available to plugins
        my \%plugin_data;
        my \@plugin_output;

        sub plugin_set {
            my (\$key, \$value) = \@_;
            \$plugin_data{\$key} = \$value;
        }

        sub plugin_get {
            my (\$key) = \@_;
            return \$plugin_data{\$key};
        }

        sub plugin_log {
            my (\$msg) = \@_;
            push \@plugin_output, \$msg;
        }

        sub get_output {
            return \\\@plugin_output;
        }

        sub get_data {
            return \\\%plugin_data;
        }

        # --- Begin Plugin Code ---
        $plugin_code
        # --- End Plugin Code ---

        # Return results
        { output => \\\@plugin_output, data => \\\%plugin_data, status => 'ok' };
    };

    # Execute with timeout protection
    my $timeout = 10;  # seconds
    my $result;
    my $error;

    eval {
        local $SIG{ALRM} = sub { die "Plugin execution timed out after ${timeout}s\n" };
        alarm($timeout);

        $result = eval($wrapped_code);
        $error = $@ if $@;

        alarm(0);
    };

    if ($@) {
        $error = $@;
        alarm(0);
    }

    if ($error) {
        log_message('ERROR', "Plugin '$plugin_name' execution failed: $error");
        return {
            success => 0,
            error   => "Execution failed: $error",
            plugin  => $plugin_name,
        };
    }

    log_message('INFO', "Plugin '$plugin_name' executed successfully");

    # Record the loaded plugin
    $loaded_plugins{$plugin_name} = {
        %$plugin,
        loaded_at => scalar localtime(),
        result    => $result,
    };

    return {
        success => 1,
        plugin  => $plugin_name,
        result  => $result,
    };
}

# ----------------------------------------------------------------------------
# Load all plugins from the plugin directory
# ----------------------------------------------------------------------------
sub load_all_plugins {
    unless (-d $PLUGIN_DIR) {
        log_message('WARN', "Plugin directory '$PLUGIN_DIR' does not exist");
        return [];
    }

    opendir(my $dh, $PLUGIN_DIR) or do {
        log_message('ERROR', "Cannot open plugin directory: $!");
        return [];
    };

    my @plugin_files = grep { /\.plugin\.conf$/ } readdir($dh);
    closedir($dh);

    my @results;
    for my $file (sort @plugin_files) {
        my $filepath = File::Spec->catfile($PLUGIN_DIR, $file);
        log_message('INFO', "Loading plugin file: $file");

        my $plugin = load_plugin_from_file($filepath);
        if ($plugin->{success}) {
            my $exec_result = execute_plugin($plugin);
            push @results, $exec_result;
        } else {
            push @results, $plugin;
            log_message('ERROR', "Failed to load plugin from $file: $plugin->{error}");
        }
    }

    return \@results;
}

# ----------------------------------------------------------------------------
# List loaded plugins
# ----------------------------------------------------------------------------
sub list_plugins {
    my @plugins;
    for my $name (sort keys %loaded_plugins) {
        my $p = $loaded_plugins{$name};
        push @plugins, {
            name        => $name,
            version     => $p->{version},
            description => $p->{description},
            author      => $p->{author},
            loaded_at   => $p->{loaded_at},
        };
    }
    return \@plugins;
}

